import React from 'react';

export default function ScheduleList({ segments, title }) {
  if (!segments?.length) {
    return null;
  }

  return (
    <div className="card mb-3">
      <div className="card-header">
        <strong>{title}</strong>
      </div>
      <div className="list-group list-group-flush">
        {segments.map((seg, idx) => {
          // Пробуем разные форматы дат
          const departureTime = formatTime(seg.departure) || formatTime(seg.departure_time) || '—';
          const arrivalTime = formatTime(seg.arrival) || formatTime(seg.arrival_time) || '—';
          const duration = formatDuration(seg.duration);
          
          return (
            <div key={idx} className="list-group-item">
              <div className="d-flex justify-content-between">
                <div>
                  <strong>{seg.thread?.number || seg.number || '—'}</strong>
                  <small className="d-block text-muted">
                    {seg.from?.title} → {seg.to?.title}
                  </small>
                  {seg.stops && (
                    <small className="d-block text-secondary mt-1">
                      Остановки: {seg.stops}
                    </small>
                  )}
                </div>
                <div className="text-end">
                  <div>
                    <strong>{departureTime}</strong>
                    <span className="text-muted mx-1">→</span>
                    <strong>{arrivalTime}</strong>
                  </div>
                  <small className="text-muted">{duration}</small>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function formatTime(dateString) {
  if (!dateString) return null;
  
  try {
    // Пробуем разные форматы
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return null;
    
    return date.toLocaleTimeString('ru-RU', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
  } catch (e) {
    return null;
  }
}

function formatDuration(seconds) {
  if (!seconds) return '';
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  return h > 0 ? `${h}ч ${m}м` : `${m}м`;
}
